            EFun fun = EFunCG.get_fun_with_handler(
            		id.module.getName(), 
            		id.function.getName(), 
            		id.arity, 
            		handler, 
            		loader);

            FunctionInfo fi = get_function_info(id);

            fi.bind(fun);

