			for ( Map.Entry<FunID,FunctionInfo> ent : binding_points.entrySet()) {
				FunID fid = ent.getKey();
				boolean is_fun = (fun == am__) || (fun == fid.function);
				boolean is_arg = argi == -1 || (argi == fid.arity);

				if (is_fun & is_arg) {
				  fis.add(ent.getValue());
