		if ((value & (OS.NID_READY | OS.NID_MULTI_INPUT)) != 0) {
			/*
			 * Feature in Windows 7: All gestures are enabled by default except GID_ROTATE.
			 * Enable it explicitly by calling SetGestureConfig.
