				GESTURECONFIG config = new GESTURECONFIG();
				config.dwID = OS.GID_ROTATE;
				config.dwWant = 1;
				config.dwBlock = 0;
				OS.MoveMemory (pConfigs, config, GESTURECONFIG.sizeof);
				OS.SetGestureConfig (handle, 0, 1, pConfigs, GESTURECONFIG.sizeof);
