		} else {
			int flags = OS.RDW_UPDATENOW | OS.RDW_ALLCHILDREN;
			OS.RedrawWindow (topHandle, null, 0, flags);
		}
		printWidget (topHandle, hdc, gc);
		if (gdipGraphics != 0) {
			OS.RestoreDC(hdc, state);
			Gdip.Graphics_ReleaseHDC(gdipGraphics, hdc);
		}
